defmodule DevOpsAutomation.CommandService do
  @allowed_commands ~w(ls pwd cat grep echo date whoami uptime df du ps top htop free uname hostname)
  
  @allowed_command_patterns [
    ~r/^ls(\s+-[altrh]+)?(\s+[\w\.\-\/]+)?$/,
    ~r/^pwd$/,
    ~r/^cat\s+[\w\.\-\/]+$/,
    ~r/^grep\s+-?\w*\s+[\w\.\-]+\s+[\w\.\-\/]+$/,
    ~r/^echo\s+[\w\s\.\-]+$/,
    ~r/^date$/,
    ~r/^whoami$/,
    ~r/^uptime$/,
    ~r/^df\s*-?[hk]?$/,
    ~r/^du\s+-?[sh]*\s*[\w\.\-\/]*$/,
    ~r/^ps\s*-?[aux]*$/,
    ~r/^free\s*-?[hm]?$/,
    ~r/^uname\s*-?[a]?$/,
    ~r/^hostname$/
  ]

  def execute_command(command_string) when is_binary(command_string) do
    with :ok <- validate_command(command_string),
         {sanitized_command, sanitized_args} <- parse_and_sanitize(command_string) do
      execute_safe_command(sanitized_command, sanitized_args)
    else
      {:error, reason} -> {:error, reason}
    end
  end

  def execute_command(_), do: {:error, :invalid_input}

  defp validate_command(command_string) do
    command_string = String.trim(command_string)
    
    cond do
      String.length(command_string) == 0 ->
        {:error, :empty_command}
      
      String.length(command_string) > 500 ->
        {:error, :command_too_long}
      
      contains_dangerous_chars?(command_string) ->
        {:error, :dangerous_characters}
      
      contains_dangerous_patterns?(command_string) ->
        {:error, :dangerous_pattern}
      
      not matches_allowed_pattern?(command_string) ->
        {:error, :command_not_allowed}
      
      true ->
        :ok
    end
  end

  defp contains_dangerous_chars?(command) do
    dangerous_chars = [";", "|", "&", "$", "`", "(", ")", "<", ">", "\n", "\r", "\\"]
    Enum.any?(dangerous_chars, &String.contains?(command, &1))
  end

  defp contains_dangerous_patterns?(command) do
    dangerous_patterns = [
      "&&", "||", "$(", "${", ">>", "<<", "2>", "1>",
      "..", "~", "*", "?", "[", "]", "{", "}"
    ]
    Enum.any?(dangerous_patterns, &String.contains?(command, &1))
  end

  defp matches_allowed_pattern?(command) do
    Enum.any?(@allowed_command_patterns, &Regex.match?(&1, command))
  end

  defp parse_and_sanitize(command_string) do
    parts = String.split(command_string, " ", trim: true)
    
    case parts do
      [command | args] ->
        if command in @allowed_commands do
          sanitized_args = Enum.map(args, &sanitize_argument/1)
          {command, sanitized_args}
        else
          {:error, :command_not_in_allowlist}
        end
      
      [] ->
        {:error, :empty_command}
    end
  end

  defp sanitize_argument(arg) do
    arg
    |> String.replace(~r/[^\w\.\-\/]/, "")
    |> String.slice(0, 255)
  end

  defp execute_safe_command(command, args) do
    case System.cmd(command, args, stderr_to_stdout: true, parallelism: true) do
      {output, 0} ->
        {:ok, output}
      
      {output, exit_code} ->
        {:error, {:command_failed, exit_code, output}}
    end
  rescue
    e in ErlangError ->
