defmodule DevOpsAutomationWeb.CommandController do
  use DevOpsAutomationWeb, :controller
  alias DevOpsAutomation.CommandService

  def execute(conn, %{"command" => command}) when is_binary(command) do
    case CommandService.execute_command(command) do
      {:ok, output} ->
        json(conn, %{
          status: "success",
          output: output,
          timestamp: DateTime.utc_now()
        })
      
      {:error, reason} ->
        conn
        |> put_status(:bad_request)
        |> json(%{
          status: "error",
          error: format_error(reason),
          timestamp: DateTime.utc_now()
        })
    end
  end

  def execute(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{
      status: "error",
      error: "Missing or invalid 'command' parameter",
      timestamp: DateTime.utc_now()
    })
  end

  defp format_error(:empty_command), do: "Command cannot be empty"
  defp format_error(:command_too_long), do: "Command exceeds maximum length"
  defp format_error(:dangerous_characters), do: "Command contains dangerous characters"
  defp format_error(:dangerous_pattern), do: "Command contains dangerous patterns"
  defp format_error(:command_not_allowed), do: "Command not in allowed list"
  defp format_error(:command_not_in_allowlist), do: "Command not permitted"
  defp format_error(:invalid_input), do: "Invalid input format"
  defp format_error({:command_failed, code, output}), do: "Command failed with exit code #{code}: #{output}"
  defp format_error({:execution_error, msg}), do: "Execution error: #{msg}"
  defp format_error({:unexpected_error, msg}), do: "Unexpected error: #{msg}"
  defp format_error(other), do: "Unknown error: #{inspect(other)}"
end